import{_ as a,o as t,c as d,a2 as s}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"配置","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/configuration.md","filePath":"zh/guide/configuration.md"}'),i={name:"zh/guide/configuration.md"};function o(c,e,n,r,l,p){return t(),d("div",null,[...e[0]||(e[0]=[s(`<h1 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h1><p>Clearance 内置了合理的默认值，因此<a href="/clearance-docs/zh/guide/installation.html">安装</a>后即可开箱使用。当你需要自定义路由前缀、中间件、上下文模型或其他任何设置时，再发布配置文件。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>这会发布 <code>config/clearance.php</code>。</p><h2 id="配置参考" tabindex="-1">配置参考 <a class="header-anchor" href="#配置参考" aria-label="Permalink to &quot;配置参考&quot;">​</a></h2><p>这是 <code>config/clearance.php</code> 中每一个键的权威参考。本文档的其他页面都会链接回这里，而不是重复这张表格。</p><table tabindex="0"><thead><tr><th>键</th><th>默认值</th><th>用途</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>所有面板路由使用的 URI 前缀。</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>在 <code>clearance.access</code> 之前应用于所有面板路由。</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>访问中间件所检查的权限。</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>默认取自 <code>auth.providers.users.model</code>。</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>用户模块的总开关（路由 + Livewire 组件）。</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code>——可以作为角色绑定上下文的模型。</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>强制执行 <code>group-action</code> 权限命名约定。</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>分隔符——仅限 <code>&#39;-&#39;</code> 或 <code>&#39;_&#39;</code>。</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>覆盖从 <code>config/auth.php</code> 自动检测到的看守器。为空 = 自动检测全部。</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>将数据库看守器注入 <code>auth.guards</code> 时所接受的驱动程序。</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>全页组件所使用的 Blade 布局。<code>null</code> = 使用宿主应用的默认布局（<code>config(&#39;livewire.layout&#39;)</code>）。</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>在 <code>Registered</code> 事件时自动分配在设置中配置的默认角色。</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>可选启用：<code>super_admin</code> 将绕过整个应用范围内的所有 Gate 检查。</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = 通过 <code>Flux::pro()</code> 自动检测。</td></tr></tbody></table><h2 id="权限命名约定" tabindex="-1">权限命名约定 <a class="header-anchor" href="#权限命名约定" aria-label="Permalink to &quot;权限命名约定&quot;">​</a></h2><p>权限必须遵循 <code>group-action</code> 格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>通过 <code>enforce_naming_convention</code> 按环境禁用此约束：</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">分隔符在启动时会被校验</p><p><code>naming_separator</code> 的值是这份配置中唯一会进入原始 SQL 片段（用于对权限进行分组/排序）的部分，因此只接受 <code>-</code> 或 <code>_</code>。</p></div><h2 id="自定义中间件" tabindex="-1">自定义中间件 <a class="header-anchor" href="#自定义中间件" aria-label="Permalink to &quot;自定义中间件&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>无论前缀或中间件如何变化，路由名称始终保持稳定——完整的路由表请参见<a href="/clearance-docs/zh/guide/quick-start.html">快速开始</a>。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/guide/quick-start.html">快速开始</a>——在应用这些设置后挂载面板</li><li><a href="/clearance-docs/zh/guide/publishing.html">发布资源</a>——发布翻译文件，以及理解 <code>layout</code> 键</li><li><a href="/clearance-docs/zh/features/guards.html">看守器</a>——<code>guards</code> 和 <code>allowed_guard_drivers</code> 的使用方式</li><li><a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>——<code>super_admin_gate_bypass</code> 的工作原理</li></ul>`,18)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
